// Normalize dispute payload across PayPal / Stripe / Klarna
const body = $input.first().json;
const headers = $input.first().headers || {};

let source = 'unknown';
if (headers['paypal-transmission-id']) source = 'paypal';
else if (headers['stripe-signature']) source = 'stripe';
else if (body.dispute_id?.startsWith('DIS')) source = 'klarna';

let dispute = {};

if (source === 'paypal') {
  const d = body.resource || {};
  dispute = {
    source: 'paypal',
    external_id: d.dispute_id,
    amount: parseFloat(d.dispute_amount?.value || 0),
    currency: d.dispute_amount?.currency_code || 'EUR',
    reason: d.reason || 'UNSPECIFIED',
    status: 'open',
    deadline: d.due_date,
    order_id: d.disputed_transactions?.[0]?.invoice_number || null,
    customer_email: d.disputed_transactions?.[0]?.buyer?.email_address || null
  };
} else if (source === 'stripe') {
  const d = body.data?.object || {};
  dispute = {
    source: 'stripe',
    external_id: d.id,
    amount: (d.amount || 0) / 100,
    currency: (d.currency || 'eur').toUpperCase(),
    reason: d.reason || 'unrecognized',
    status: 'open',
    deadline: d.evidence_details?.due_by ? new Date(d.evidence_details.due_by * 1000).toISOString() : null,
    order_id: d.payment_intent || null,
    customer_email: null
  };
} else {
  // Generic fallback
  dispute = {
    source: source,
    external_id: body.id || body.dispute_id,
    amount: body.amount || 0,
    currency: body.currency || 'EUR',
    reason: body.reason || 'unknown',
    status: 'open',
    deadline: body.due_date || null,
    order_id: body.order_id || null,
    customer_email: body.customer_email || null
  };
}

return [{ json: dispute }];
